import { readFileSync } from "node:fs";
import path from "node:path";
import Link from "next/link";
import { notFound } from "next/navigation";
import { requireSession } from "@/lib/auth-helpers";

export const metadata = {
  title: "Coverage — EHC Admin",
  robots: { index: false, follow: false },
};

// Campaign-scoped coverage reports. The HTML is generated by the Python
// pipeline (~/ehc-press/tools/build_coverage_report.py) and committed into
// this repo under content/coverage/<campaign>.html by
// tools/publish_coverage_to_ehc.py. Served here behind the admin session
// gate (proxy.ts matches /admin/*, and requireSession() below is
// defence-in-depth) instead of the old public /2026-ehsa-press/ basic-auth
// route, which lost its wall when middleware.ts was deleted in the auth flip.
//
// Known campaigns are listed explicitly so an arbitrary ?campaign= can't be
// used to probe the filesystem.
const REPORTS: Record<string, { label: string; file: string; summary?: string }> = {
  "ehsa-2026": {
    label: "EHSA 2026",
    file: "ehsa-2026.html",
    summary: "ehsa-2026-summary.html",
  },
};

function loadReport(file: string): string | null {
  try {
    return readFileSync(
      path.join(process.cwd(), "content", "coverage", file),
      "utf8",
    );
  } catch {
    return null;
  }
}

export default async function CoveragePage({
  params,
  searchParams,
}: {
  params: Promise<{ campaign: string }>;
  searchParams: Promise<{ view?: string }>;
}) {
  await requireSession();

  const { campaign } = await params;
  const { view } = await searchParams;
  const report = REPORTS[campaign];
  if (!report) notFound();

  const wantSummary = view === "summary" && report.summary;
  const file = wantSummary ? report.summary! : report.file;
  const html = loadReport(file);

  return (
    <div style={{ background: "#fafafa", minHeight: "100vh", color: "#111" }}>
      <div className="bg-ink text-white text-[12px]">
        <div className="max-w-6xl mx-auto px-6 h-9 flex items-center justify-between">
          <span className="tracking-[0.18em] uppercase text-[10.5px] opacity-80 font-medium">
            {report.label} · Coverage
          </span>
          <div className="flex gap-5 opacity-80">
            <Link
              href={`/admin/coverage/${campaign}`}
              className="hover:opacity-100"
              style={{ fontWeight: wantSummary ? 400 : 700 }}
            >
              Report
            </Link>
            {report.summary ? (
              <Link
                href={`/admin/coverage/${campaign}?view=summary`}
                className="hover:opacity-100"
                style={{ fontWeight: wantSummary ? 700 : 400 }}
              >
                Summary
              </Link>
            ) : null}
            <Link href="/admin" className="hover:opacity-100">
              Press
            </Link>
          </div>
        </div>
      </div>

      {html ? (
        <iframe
          title={`${report.label} coverage`}
          srcDoc={html}
          style={{
            width: "100%",
            height: "calc(100vh - 36px)",
            border: "none",
            display: "block",
          }}
        />
      ) : (
        <div style={{ maxWidth: 640, margin: "12vh auto", padding: "0 24px" }}>
          <h1 style={{ fontSize: 22, fontWeight: 600, marginBottom: 8 }}>
            No report published yet
          </h1>
          <p style={{ color: "#666", fontSize: 14, lineHeight: 1.55 }}>
            The <code>{report.label}</code> coverage report isn&apos;t on disk.
            Regenerate it in <code>~/ehc-press</code> and run{" "}
            <code>python3 tools/publish_coverage_to_ehc.py</code>, then commit{" "}
            <code>content/coverage/</code>.
          </p>
        </div>
      )}
    </div>
  );
}
